     9→import { BaseCategoryCorrelationDto } from '@modules/db/category-correlations/dto/category-correlation.base.dto';
    10→import { ICategoryCorrelationBase } from '@modules/db/category-correlations/types/category-correlation.base.interface';
    11→
    12→import {
    13→	KNEX_READ_CONNECTION,
    14→	KNEX_WRITE_CONNECTION,
    15→	TABLE_NAME_CATEGORIES_CORRELATIONS,
    16→} from '@constants/db.constant';
    17→
    18→@Injectable()
    19→export class CategoryCorrelationModel {
    20→	private readonly logger = new Logger(CategoryCorrelationModel.name);
    21→	private readonly tableName = TABLE_NAME_CATEGORIES_CORRELATIONS;
    22→
    23→	constructor(
    24→		@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
    25→		@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
    26→	) {}
    27→
    28→	async findTopCorrelatedCategories({
    29→		primaryCategoryId,
    30→		limit = 4,
    31→		exclude,
    32→	}: {
    33→		primaryCategoryId: ICategoryCorrelationBase['primary_category_id'];
    34→		limit?: number;
    35→		exclude?: number[];
    36→	}): Promise<ICategoryCorrelationBase[]> {
    37→		try {
    38→			let query = this.knexRead<BaseCategoryCorrelationDto>(this.tableName)
    39→				.where({ primary_category_id: primaryCategoryId })
    40→				.whereNull('deleted_at');
    41→
    42→			if (exclude && exclude.length > 0) {
    43→				query = query.whereNotIn('edge_id', exclude);
    44→			}
    45→
    46→			const results = await query.orderBy('edge_weight', 'desc').limit(limit);
    47→
    48→			this.logger.debug(
    49→				`Found ${results.length} correlated categories for category ${primaryCategoryId}`,
    50→			);
    51→
    52→			const validatedResults = await Promise.all(
    53→				results.map(async (result) => {
    54→					const dto = plainToInstance(BaseCategoryCorrelationDto, result);
    55→					const errors = await validate(dto);
    56→					if (errors.length > 0) {
    57→						this.logger.error(
    58→							`Validation failed for category correlation data: ${this.formatValidationErrors(errors)}`,
    59→						);
    60→						throw new Error(`Validation failed: ${this.formatValidationErrors(errors)}`);
    61→					}
    62→					return instanceToPlain<BaseCategoryCorrelationDto>(
    63→						result,
    64→					) as ICategoryCorrelationBase;
    65→				}),
    66→			);
    67→
    68→			return validatedResults;
    69→		} catch (error) {
    70→			this.logger.error(
    71→				`Failed to find correlated categories for category ${primaryCategoryId}: ${(error as Error).message}`,
    72→			);
    73→			throw error;
    74→		}
    75→	}
    76→
    77→	async bulkUpsert(
    78→		correlations: {
    79→			primaryCategoryId: number;
    80→			edgeId: number;
    81→			edgeWeight: number;
    82→		}[],
    83→	): Promise<void> {
    84→		try {
    85→			const dataToInsert = correlations.map((correlation) => ({
    86→				_id: randomUUID(),
    87→				primary_category_id: correlation.primaryCategoryId,
    88→				edge_id: correlation.edgeId,
    89→				edge_weight: correlation.edgeWeight,
    90→				created_at: this.knexWrite.fn.now(),
    91→				updated_at: this.knexWrite.fn.now(),
    92→				deleted_at: null,
    93→			}));
    94→
    95→			const batchSize = 1000;
    96→			for (let i = 0; i < dataToInsert.length; i += batchSize) {
    97→				const batch = dataToInsert.slice(i, i + batchSize);
    98→
    99→				await this.knexWrite(this.tableName)
   100→					.insert(batch)
   101→					.onConflict(['primary_category_id', 'edge_id'])
   102→					.merge(['edge_weight', 'updated_at', 'deleted_at']);
   103→
   104→				this.logger.debug(
   105→					`Processed batch ${Math.floor(i / batchSize) + 1}/${Math.ceil(dataToInsert.length / batchSize)} (${batch.length} records)`,
   106→				);
   107→			}
   108→
   109→			this.logger.log(
   110→				`Successfully upserted ${correlations.length} category correlations`,
   111→			);
   112→		} catch (error) {
   113→			this.logger.error(
   114→				`Failed to bulk upsert category correlations: ${(error as Error).message}`,
   115→			);
   116→			throw error;
   117→		}
   118→	}
   119→
   120→	async clearExistingData(): Promise<void> {
   121→		try {
   122→			const deletedCount = await this.knexWrite(this.tableName)
   123→				.whereNotNull('_id')
   124→				.whereNull('deleted_at')
   125→				.update({
   126→					deleted_at: this.knexWrite.fn.now(),
   127→					updated_at: this.knexWrite.fn.now(),
   128→				});
   129→
   130→			this.logger.log(
   131→				`Soft deleted ${deletedCount} existing category correlation records`,
   132→			);
   133→		} catch (error) {
   134→			this.logger.error(
   135→				`Failed to clear existing category correlations: ${(error as Error).message}`,
   136→			);
   137→			throw error;
   138→		}
   139→	}
   140→
   141→	async getRecordCount(): Promise<number> {
   142→		try {
   143→			const result = await this.knexRead(this.tableName)
   144→				.whereNull('deleted_at')
   145→				.count('_id as count')
   146→				.first();
   147→
   148→			return Number(result?.['count'] ?? 0);
   149→		} catch (error) {
   150→			this.logger.error(
   151→				`Failed to get record count for category correlations: ${(error as Error).message}`,
   152→			);
   153→			throw error;
   154→		}
   155→	}
   156→
   157→	private formatValidationErrors(errors: ValidationError[]): string {
   158→		return errors
   159→			.map(
   160→				(error) =>
   161→					`${error.property}: ${Object.values(error.constraints ?? {}).join(', ')}`,
   162→			)
   163→			.join('; ');
   164→	}
   165→}
